const todasGuias = $input.all();

const guiasFiltradas = todasGuias.filter(item => {
  const statusGuide = (item.json.status_guide || '').toString().toUpperCase().trim();
  const statusXml = (item.json.status_xml || '').toString().toUpperCase().trim();
  return statusGuide === 'COMPLETA' && statusXml === 'PENDENTE';
});

if (guiasFiltradas.length === 0) {
  return [{ json: { temGuias: false, mensagem: 'Nenhuma guia pendente' } }];
}

console.log('Guias a processar:', guiasFiltradas.length);

return [{
  json: {
    temGuias: true,
    guias: guiasFiltradas.map(item => String(item.json.guide_number)),
    totalGuias: guiasFiltradas.length,
    API_URL: 'http://puppeteer-api:3001'
  }
}];

const redisValue = $input.first().json.value;
const dados = $('2. Preparar Lista de Guias').first().json;

let cookies = null;
let temCookies = false;

if (redisValue && redisValue !== '' && redisValue !== 'null') {
  try {
    const parsed = JSON.parse(redisValue);
    cookies = parsed.cookies || parsed;
    temCookies = Array.isArray(cookies) && cookies.length > 0;

    const temJSession = cookies.some(c => c.name === 'JSESSIONID');
    if (!temJSession) {
      temCookies = false;
      cookies = null;
    }
  } catch (e) {
    console.log('Erro parse cookies:', e.message);
  }
}

return [{
  json: {
    ...dados,
    cookies,
    temCookies
  }
}];

const loginResult = $input.first().json;
const dados = $('4. Parse Cookies').first().json;

if (!loginResult.success) {
  return [{ json: { ...dados, cookies: null, temCookies: false, erroLogin: loginResult.erro } }];
}

return [{
  json: {
    ...dados,
    cookies: loginResult.cookies,
    temCookies: true,
    loginFresh: true
  }
}];

// IMPORTANTE: Este node recebe de 2 fontes:
// 1. Sessão OK? (TRUE) → input é resposta do testar-sessao (NÃO tem guias)
// 2. 5c. Redis SET Cookies → input é resultado do Redis (NÃO tem guias)
// Por isso, SEMPRE busca guias/API_URL do node 4. Parse Cookies
// E cookies do 5b. Processar Login (se fez login) ou do 4. Parse Cookies

const dadosBase = $('4. Parse Cookies').first().json;
const guias = dadosBase.guias || [];
const API_URL = dadosBase.API_URL;

// Tenta pegar cookies do login (se passou pelo fluxo de login)
let cookies = dadosBase.cookies;
try {
  const loginData = $('5b. Processar Login').first().json;
  if (loginData && loginData.cookies) {
    cookies = loginData.cookies;
    console.log('Usando cookies do login fresh');
  }
} catch(e) {
  // Não passou pelo login, usa cookies do Redis (já no dadosBase)
  console.log('Usando cookies do Redis cache');
}

console.log('Separando', guias.length, 'guias em items individuais');

return guias.map(numeroGuia => ({
  json: {
    numeroGuia: String(numeroGuia),
    cookies: cookies,
    API_URL: API_URL
  }
}));

// Busca falhou - pega dados da guia atual do Loop
// O input vem do Busca OK? (FALSE) que recebeu a resposta HTTP com erro
const dados = $json;

// Tenta pegar o numero da guia
let numeroGuia = dados.numeroGuia;
if (!numeroGuia) {
  try {
    numeroGuia = $('8. Buscar XML (API)').first().json.numeroGuia;
  } catch(e) {
    numeroGuia = 'desconhecida';
  }
}

return [{
  json: {
    guide_number: String(numeroGuia),
    status_xml: 'ERRO: ' + (dados.erro || dados.message || 'Falha ao buscar XML')
  }
}];

const r = $json;

if (!r.xmlContent) {
  return [{ json: { _skip: true, numeroGuia: r.numeroGuia } }];
}

return [{ json: r }];

const r = $json;

if (r._skip) {
  return [{ json: { _skip: true, numeroGuia: r.numeroGuia } }];
}

const xml = r.xmlContent;

function getTag(tagName) {
  const regex = new RegExp(`<ans:${tagName}>(.*?)</ans:${tagName}>`, 's');
  const match = xml.match(regex);
  return match ? match[1].trim() : '';
}

function getNested(parent, child) {
  const pRegex = new RegExp(`<ans:${parent}>(.*?)</ans:${parent}>`, 's');
  const pMatch = xml.match(pRegex);
  if (!pMatch) return '';
  const cRegex = new RegExp(`<ans:${child}>(.*?)</ans:${child}>`, 's');
  const cMatch = pMatch[1].match(cRegex);
  return cMatch ? cMatch[1].trim() : '';
}

return [{
  json: {
    'Nº Guia Operadora': "'" + getTag('numeroGuiaOperadora'),
    'Nº Guia Prestador': "'" + getTag('numeroGuiaPrestador'),
    'Data Autorização': getTag('dataAutorizacao'),
    'Senha': "'" + getTag('senha'),
    'Validade Senha': getTag('dataValidadeSenha'),
    'Nº Carteira': "'" + getTag('numeroCarteira'),
    'Nome Beneficiário': getTag('nomeBeneficiario'),
    'Data Solicitação': getTag('dataSolicitacao'),
    'Código Prestador': getNested('contratadoSolicitante', 'codigoPrestadorNaOperadora'),
    'Nome Prestador': getNested('contratadoSolicitante', 'nomeContratado'),
    'CNES': getNested('dadosExecutante', 'CNES'),
    'Nome Profissional': getNested('profissionalSolicitante', 'nomeProfissional'),
    'Conselho': getNested('profissionalSolicitante', 'conselhoProfissional'),
    'Nº Conselho': getNested('profissionalSolicitante', 'numeroConselhoProfissional'),
    'UF': getNested('profissionalSolicitante', 'UF'),
    'CBOS': getNested('profissionalSolicitante', 'CBOS'),
    'Tipo Atendimento': getTag('tipoAtendimento'),
    'Indicação Acidente': getTag('indicacaoAcidente'),
    'Indicação Clínica': getTag('indicacaoClinica'),
    'Valor Total Geral': getTag('valorTotalGeral'),
    'Status': 'Importado',
    'Data Importação': new Date().toISOString(),
    'cadastrada': 'SIM',
    'numeroGuia': r.numeroGuia,
    'xmlContent': xml
  }
}];

const dados = $json;

if (dados._skip) {
  return [{ json: { _skip: true, numeroGuia: dados.numeroGuia } }];
}

const xml = dados.xmlContent;

function getTag(tagName) {
  const regex = new RegExp(`<ans:${tagName}>(.*?)</ans:${tagName}>`, 's');
  const match = xml.match(regex);
  return match ? match[1].trim() : '';
}

function getNested(parent, child) {
  const pRegex = new RegExp(`<ans:${parent}>(.*?)</ans:${parent}>`, 's');
  const pMatch = xml.match(pRegex);
  if (!pMatch) return '';
  const cRegex = new RegExp(`<ans:${child}>(.*?)</ans:${child}>`, 's');
  const cMatch = pMatch[1].match(cRegex);
  return cMatch ? cMatch[1].trim() : '';
}

const numeroGuiaOperadora = getTag('numeroGuiaOperadora');
const numeroGuiaPrestador = getTag('numeroGuiaPrestador');
const nomeBeneficiario = getTag('nomeBeneficiario');
const nomeProfissional = getNested('profissionalSolicitante', 'nomeProfissional');
const conselho = getNested('profissionalSolicitante', 'conselhoProfissional');
const numeroConselho = getNested('profissionalSolicitante', 'numeroConselhoProfissional');
const uf = getNested('profissionalSolicitante', 'UF');
const cbos = getNested('profissionalSolicitante', 'CBOS');

const procedimentosRegex = /<ans:procedimentoExecutado>(.*?)<\/ans:procedimentoExecutado>/gs;
const matches = [...xml.matchAll(procedimentosRegex)];

if (matches.length === 0) {
  return [{ json: { _noProcedimentos: true, numeroGuia: dados.numeroGuia } }];
}

const procedimentos = matches.map((match, index) => {
  const procXML = match[1];

  function getProcTag(tagName) {
    const regex = new RegExp(`<ans:${tagName}>(.*?)</ans:${tagName}>`, 's');
    const m = procXML.match(regex);
    return m ? m[1].trim() : '';
  }

  const descricao = getProcTag('descricaoProcedimento');
  let valorUnitario = 30.36;
  if (descricao.toLowerCase().includes('psicomotricidade') || descricao.toLowerCase().includes('psicomotricista')) {
    valorUnitario = 70.00;
  } else if (descricao.toLowerCase().includes('fonoaudi')) {
    valorUnitario = 35.00;
  }

  const qtd = parseFloat(getProcTag('quantidadeExecutada') || 1);

  return {
    'Chave': numeroGuiaOperadora + '-' + (index + 1),
    'Nº Guia Operadora': "'" + numeroGuiaOperadora,
    'Nº Guia Prestador': "'" + numeroGuiaPrestador,
    'Sequência': index + 1,
    'Nome Beneficiário': nomeBeneficiario,
    'Data Execução': getProcTag('dataExecucao'),
    'Hora Início': getProcTag('horaInicial'),
    'Hora Fim': getProcTag('horaFinal'),
    'Código Tabela': getProcTag('codigoTabela'),
    'Código Procedimento': "'" + getProcTag('codigoProcedimento'),
    'Descrição Procedimento': descricao,
    'Quantidade Executada': qtd,
    'Via Acesso': getProcTag('viaAcesso'),
    'Técnica Utilizada': getProcTag('tecnicaUtilizada'),
    'Redução/Acréscimo': getProcTag('reducaoAcrescimo'),
    'Valor Unitário': valorUnitario.toFixed(2),
    'Valor Total': (valorUnitario * qtd).toFixed(2),
    'Nome Profissional': nomeProfissional,
    'Conselho': conselho,
    'Nº Conselho': numeroConselho,
    'UF': uf,
    'CBOS': cbos,
    'Status': 'Importado',
    'Data Importação': new Date().toISOString()
  };
});

return procedimentos.map(p => ({ json: p }));

// Pega o numero da guia atual do loop
const buscaResult = $('8. Buscar XML (API)').first().json;
const numeroGuia = buscaResult.numeroGuia || 'desconhecida';
const success = buscaResult.success;

return [{
  json: {
    guide_number: numeroGuia,
    status_xml: success ? 'COLETADA' : ('ERRO: ' + (buscaResult.erro || 'Falha'))
  }
}];

// Relatório final após todas as guias processadas
const totalGuias = $('7. Separar Guias em Array').first().json;

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    mensagem: 'Processamento concluído'
  }
}];
